commands.command:
# Windows'ta IOC tarama (PowerShell):
# Bilinen zararlı hash ile tüm dosyaları tara:
$zararlı_hash = '44d88612fea8a8f36de82e1278abb02f'
Get-ChildItem -Recurse C:\Users -ErrorAction SilentlyContinue | ForEach-Object {
  $hash = (Get-FileHash $_.FullName -Algorithm MD5 -ErrorAction SilentlyContinue).Hash
  if ($hash -eq $zararlı_hash) {
    Write-Host "[BULUNDU] $($_.FullName)" -ForegroundColor Red
  }
}
